CREATE TABLE IF NOT EXISTS banks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email TEXT UNIQUE NOT NULL, phone TEXT, full_name TEXT, role TEXT NOT NULL, locale TEXT DEFAULT 'es', bank_id UUID REFERENCES banks(id), created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS applications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), applicant_id UUID REFERENCES users(id), bank_id UUID REFERENCES banks(id), status TEXT DEFAULT 'in_progress', property_address TEXT, loan_amount_usd NUMERIC(12,2), created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS documents (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), application_id UUID REFERENCES applications(id), doc_type TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', s3_key TEXT, s3_iv TEXT, original_filename TEXT, file_size_bytes INTEGER, mime_type TEXT, uploaded_at TIMESTAMPTZ, reviewed_at TIMESTAMPTZ, reviewed_by UUID REFERENCES users(id), rejection_reason TEXT, expires_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS auth_tokens (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES users(id), token_hash TEXT NOT NULL, expires_at TIMESTAMPTZ NOT NULL, used_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_log (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), actor_id UUID REFERENCES users(id), action TEXT NOT NULL, entity_type TEXT, entity_id UUID, metadata JSONB, created_at TIMESTAMPTZ DEFAULT now());
